-- PersonRepository.getPeopleOverviewStatistics
WITH
  "eligible_faces" AS (
    SELECT
      "asset_face"."id" AS "assetFaceId",
      "asset_face"."personId"
    FROM
      "asset_face"
      INNER JOIN "asset" ON "asset"."id" = "asset_face"."assetId"
    WHERE
      "asset"."ownerId" = $1
      AND "asset"."deletedAt" IS NULL
      AND "asset"."isOffline" = false
      AND "asset"."visibility" IN ($2, $3)
      AND "asset_face"."deletedAt" IS NULL
      AND "asset_face"."isVisible" = true
  ),
  "eligible_people" AS (
    SELECT
      "person"."id",
      "person"."isHidden"
    FROM
      "person"
      INNER JOIN "eligible_faces" ON "eligible_faces"."personId" = "person"."id"
    WHERE
      "person"."ownerId" = $4
    GROUP BY
      "person"."id"
    HAVING
      NULLIF(BTRIM("person"."name"), '') IS NOT NULL
      OR COUNT(DISTINCT "eligible_faces"."assetFaceId") >= $5
  )
SELECT
  COUNT(DISTINCT "eligible_people"."id")::int AS "total",
  COUNT(DISTINCT "eligible_people"."id") FILTER (
    WHERE
      "eligible_people"."isHidden" = true
  )::int AS "hidden",
  COUNT(DISTINCT "eligible_faces"."assetFaceId")::int AS "detectedFaceCount"
FROM
  "eligible_faces"
  LEFT JOIN "eligible_people" ON "eligible_people"."id" = "eligible_faces"."personId"

-- PersonRepository.getPeopleFaceStatistics
WITH
  "eligible_faces" AS (
    SELECT
      "asset_face"."id" AS "assetFaceId",
      "asset_face"."personId"
    FROM
      "asset_face"
      INNER JOIN "asset" ON "asset"."id" = "asset_face"."assetId"
    WHERE
      "asset"."ownerId" = $1
      AND "asset"."deletedAt" IS NULL
      AND "asset"."isOffline" = false
      AND "asset"."visibility" IN ($2, $3)
      AND "asset_face"."deletedAt" IS NULL
      AND "asset_face"."isVisible" = true
  ),
  "person_face_counts" AS (
    SELECT
      "personId",
      COUNT(DISTINCT "assetFaceId")::int AS "assetCount"
    FROM
      "eligible_faces"
    WHERE
      "personId" IS NOT NULL
    GROUP BY
      "personId"
  ),
  "detected_faces" AS (
    SELECT
      "eligible_faces"."assetFaceId",
      "person"."id" AS "personId",
      NULLIF(BTRIM("person"."name"), '') IS NOT NULL AS "isNamed",
      CASE
        WHEN "person"."id" IS NOT NULL
        AND (
          NULLIF(BTRIM("person"."name"), '') IS NOT NULL
          OR "person_face_counts"."assetCount" >= $4
        ) THEN "person"."isHidden"
        ELSE NULL
      END AS "isHidden"
    FROM
      "eligible_faces"
      LEFT JOIN "person" ON "person"."id" = "eligible_faces"."personId"
      AND "person"."ownerId" = $5
      LEFT JOIN "person_face_counts" ON "person_face_counts"."personId" = "person"."id"
  )
SELECT
  COUNT(DISTINCT "assetFaceId")::int AS "detectedFaceCount",
  COUNT(DISTINCT "assetFaceId") FILTER (
    WHERE
      "isHidden" = false
  )::int AS "assignedVisibleFaceCount",
  COUNT(DISTINCT "personId") FILTER (
    WHERE
      "isHidden" = false
      AND "isNamed" = true
  )::int AS "namedVisiblePersonCount",
  COUNT(DISTINCT "assetFaceId") FILTER (
    WHERE
      "isHidden" = true
  )::int AS "assignedHiddenFaceCount",
  COUNT(DISTINCT "assetFaceId") FILTER (
    WHERE
      "isHidden" IS NULL
  )::int AS "unassignedFaceCount"
FROM
  "detected_faces"

